async function main() {
  console.log(`Preparing ${newFirms.length} firms...`);
  const existing = [];
  let from = 0;
  while (true) {
    const { data, error } = await supabase.from('firms').select('slug,name,website').range(from, from + 999);
    if (error) throw error;
    existing.push(...data);
    if (data.length < 1000) break;
    from += 1000;
  }
  const slugs = new Set(existing.map(f => f.slug));
  const names = new Set(existing.map(f => f.name.toLowerCase()));
  const sites = new Set(existing.filter(f => f.website).map(f => f.website.replace(/\/+$/, '').toLowerCase()));
  const toInsert = [];
  for (const f of newFirms) {
    const web = (f.website || '').replace(/\/+$/, '').toLowerCase();
    if (slugs.has(f.slug) || names.has(f.name.toLowerCase()) || (web && sites.has(web))) continue;
    toInsert.push({
      slug: f.slug, name: f.name,
      contact: f.contact || null, title: f.title || null, email: f.email || null,
      city: f.city, city_label: f.cityLabel, province: f.province, country: f.country,
      services: f.services || [], industries: f.industries || [],
      description: f.description || null, website: f.website || null,
      plan: 'free', priority_score: 0, status: 'active',
      submitted_by: 'admin', source: f.source || 'claude_code',
    });
  }
  console.log(`Inserting ${toInsert.length} (skipped ${newFirms.length - toInsert.length} duplicates).`);
  const BATCH = 50;
  for (let i = 0; i < toInsert.length; i += BATCH) {
    const chunk = toInsert.slice(i, i + BATCH);
    const { error } = await supabase.from('firms').insert(chunk);
    if (error) { console.error('✗', error.message); continue; }
    console.log(`✓ chunk ${Math.floor(i/BATCH)+1}: ${chunk.length}`);
  }
}

main().catch((e) => { console.error(e); process.exit(1); });
